using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");
            entity.HasIndex(p => p.Sku);

            // EF Core 9 renamed the discriminator property from "Discriminator" to "$type".
            // Preserve the old name so existing 500K documents remain queryable without migration.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed id format from "EntityType|Key" to just "Key".
            // Preserve the old format so existing documents (e.g. "Product|123") are still found.
            entity.Property(p => p.Id).HasJsonPropertyName("id");
            entity.HasPartitionKey(p => p.Id);
        });

        // Keep legacy id format: "Product|<key>"
        modelBuilder.Entity<Product>().Property(p => p.Id)
            .HasValueGenerator<LegacyIdValueGenerator>();
    }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        // Opt out of the simplified id-generation so existing "Product|123" ids still resolve.
        // This is a global switch in EF Core 9 Cosmos provider.
    }
}

